import React, { useState } from "react";
import API from "../api";

const DetectDisease = () => {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) return alert("Please upload an image first!");

    const formData = new FormData();
    formData.append("image", file);

    try {
      const res = await API.post("/api/detect", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      setResult(res.data.result);
    } catch (err) {
      alert("Error detecting disease!");
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gray-50 p-6">
      <h2 className="text-3xl font-bold text-green-600 mb-6">Crop Disease Detection</h2>

      <form onSubmit={handleSubmit} className="bg-white shadow-lg p-8 rounded-xl w-96">
        <input
          type="file"
          accept="image/*"
          onChange={(e) => setFile(e.target.files[0])}
          className="mb-4"
        />

        <button
          type="submit"
          className="bg-green-600 text-white w-full py-2 rounded-lg hover:bg-green-700"
        >
          Upload & Detect
        </button>
      </form>

      {result && (
        <div className="mt-6 bg-green-50 p-4 rounded-lg shadow-md text-center w-96">
          <p className="text-lg text-gray-800">Result: {result}</p>
        </div>
      )}
    </div>
  );
};

export default DetectDisease;
